-- Migration: Create Quotation Leads CRM Table
-- Date: 2026-06-29

CREATE TABLE IF NOT EXISTS public.quotation_leads (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    ref_no TEXT NOT NULL UNIQUE,
    created_date DATE NOT NULL DEFAULT CURRENT_DATE,
    client_name TEXT NOT NULL DEFAULT '',
    phone TEXT DEFAULT '',
    site_project TEXT DEFAULT '',
    area_sqft NUMERIC DEFAULT 0,
    quote_value NUMERIC DEFAULT 0,
    status TEXT NOT NULL DEFAULT 'Draft' CHECK (status IN ('Draft', 'Sent', 'Follow-up', 'Approved', 'Rejected', 'On Hold')),
    approved_value NUMERIC DEFAULT 0,
    assigned_by TEXT DEFAULT '',
    follow_up_1 TEXT DEFAULT '',
    follow_up_2 TEXT DEFAULT '',
    follow_up_3 TEXT DEFAULT '',
    remarks TEXT DEFAULT '',
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Enable RLS
ALTER TABLE public.quotation_leads ENABLE ROW LEVEL SECURITY;

-- Select policy: Allow authenticated users to view leads
CREATE POLICY "Allow select for authenticated users on crm" 
    ON public.quotation_leads FOR SELECT 
    TO authenticated 
    USING (true);

-- Insert/Update/Delete policy: Allow authenticated users to manage leads
CREATE POLICY "Allow write for authenticated users on crm" 
    ON public.quotation_leads FOR ALL 
    TO authenticated 
    USING (true)
    WITH CHECK (true);

-- Seed initial leads (116 leads till date)
ON CONFLICT (ref_no) DO NOTHING;
